const data = $input.first().json;
const results = data.local_results || [];
if (results.length === 0) throw new Error('Dükkan bulunamadi!');
const p = results[0];
return [{json:{dataId:p.data_id||'',title:p.title||'',rating:p.rating||0,totalReviews:p.reviews||0,address:p.address||''}}];

const data = $input.first().json;
const info = $('Dükkan Bilgisi Çıkar').first().json;
const reviews = data.reviews || [];
const tarih = new Date().toLocaleDateString('tr-TR');
if (reviews.length === 0) return [{json:{promptText:'Yorum yok',yorumlar:[],tarih,dukkan:info.title,puan:info.rating}}];
const yorumlar = reviews.slice(0,10).map((r,i)=>({
  sira:i+1, yazar:r.user?.name||'Anonim', puan:r.rating||0,
  yTarih:r.date||'', metin:(r.snippet||r.extracted_snippet?.original||'').substring(0,300)
}));
const txt = yorumlar.map(y=>y.sira+'.['+y.puan+'/5]'+y.yazar+':'+y.metin).join('|||');
const promptText='Sen restoran yorum analiz uzmanisin. Turkce yanit ver. Dukkan:'+info.title+' ('+info.rating+'/5). '+yorumlar.length+' yorumu analiz et: '+txt+'. Her yorum icin JSON dizisi ver (SADECE JSON): [{"sira":1,"duygu":"Olumlu/Olumsuz/Notr","kategori":"Yemek/Servis/Hijyen/Fiyat/Ortam/Genel","ozet":"Kisa ozet","oneri":"Dukkan sahibine oneri","acil":true/false}] Kurallar: 1-2 puan=Olumsuz+acil. 4-5=Olumlu. Hijyen sikayeti=her zaman acil.';
return [{json:{promptText,yorumlar,tarih,dukkan:info.title,puan:info.rating,toplamYorum:info.totalReviews}}];

const gemini=$input.first().json;
const prev=$('Rate Limit').first().json;
const yorumlar=prev.yorumlar||[];
let analizler=[];
try{
  let t=gemini.candidates[0].content.parts[0].text;
  const m=t.match(/\[\s*\{[\s\S]*\}\s*\]/);
  if(m) analizler=JSON.parse(m[0]);
}catch(e){
  analizler=yorumlar.map((_,i)=>({sira:i+1,duygu:'Notr',kategori:'Genel',ozet:'Analiz yapilamadi',oneri:'',acil:false}));
}
const sonuclar=[];
let olumsuzVar=false;
for(let i=0;i<yorumlar.length;i++){
  const y=yorumlar[i];
  const a=analizler[i]||{duygu:'Notr',kategori:'Genel',ozet:'',oneri:'',acil:false};
  if(a.duygu==='Olumsuz'||a.acil) olumsuzVar=true;
  sonuclar.push({json:{
    tarih:prev.tarih,dukkan:prev.dukkan,genelPuan:prev.puan,
    yazar:y.yazar,puan:y.puan,yorumTarihi:y.yTarih,yorum:y.metin,
    duygu:a.duygu||'Notr',kategori:a.kategori||'Genel',
    ozet:a.ozet||'',oneri:a.oneri||'',acil:a.acil?'Evet':'Hayir',olumsuzVar
  }});
}
return sonuclar.length>0?sonuclar:[{json:{tarih:prev.tarih,dukkan:prev.dukkan,yazar:'Yok',puan:0,yorum:'Yeni yorum yok',duygu:'Notr',kategori:'Genel',ozet:'',oneri:'',acil:'Hayir',olumsuzVar:false}}];

const items=$input.all();
const d0=items[0]?.json||{};
let m='\ud83d\udea8 OLUMSUZ YORUM TESPIT EDILDI!\n\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\n';
m+='\ud83c\udf56 '+(d0.dukkan||'Durule')+' | \u2b50 '+(d0.genelPuan||'')+'/5\n';
m+='\ud83d\udcc5 '+(d0.tarih||'')+'\n\n';
const neg=items.filter(i=>i.json.duygu==='Olumsuz'||i.json.acil==='Evet');
neg.forEach(item=>{
  const d=item.json;
  const e=d.acil==='Evet'?'\ud83d\udd34':'\ud83d\udfe1';
  m+=e+' '+d.yazar+' ('+d.puan+'/5)\n';
  m+='   \ud83d\udcac '+d.yorum.substring(0,150)+'\n';
  m+='   \ud83d\udcdd '+d.ozet+'\n';
  m+='   \ud83d\udca1 '+d.oneri+'\n\n';
});
m+='\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\n\ud83e\udd16 Durule Yorum Takip Sistemi';
return [{json:{mesaj:m}}];
